declare module 'network' {
    type Interface = {
        name: string
        ip_address: string
        netmask: string
    }

    const module: {
        get_active_interface: (callback: (error: Error | null, interface: Interface) => void) => void
    };

    export default module;
}

declare module 'network-calculator' {
    const module: (ip: string, netmask: string) => ({
        network: string
        bitmask: number
        firsthost: string
        broadcast: string
        lasthost: string
        totalhost: number
    });
    export default module;
}

declare module 'node-arp' {
    const module: {
        getMAC: (ip: string, callback: (error: null | Error, mac?: string) => void) => void;
    };
    export default module;
}

declare module 'node-dns-sd' {
    type discoverParams = {
        name: string | string[],
        type?: string | null | undefined,
        key?: 'address' | 'fqdn' | undefined,
        wait?: number | undefined,
        quick?: boolean | undefined,
        filter?: string | ((device: { fqdn: string, address: string }) => boolean) | undefined
    };
    type Packet = {
      header: any,
      questions: [],
      answers: any[],
      authorities: [],
      additionals: any[],
      address: string
    };
    type device = {
        fqdn: string | null,
        address: string | null,
        packet: Packet,
    }
    const DnsSd: {
        discover: ((params: discoverParams) => Promise<device[]>)
    };
    export default DnsSd;
}